import { questions } from "../data/questions";

function Dashboard() {
  return (
    <div className="page-center">
      <div className="card">
        <h2>Dashboard</h2>

        {questions.map((q) => (
          <div key={q.id} className="list-card">
            <h4>{q.title}</h4>
            <p>{q.description}</p>
            <a className="link" href="/answers">View Answer</a>
          </div>
        ))}

        <a className="btn" href="/ask">Ask Question</a>
      </div>
    </div>
  );
}

export default Dashboard;
